package deps

import (
	"fmt"
	"strings"
)

// ComponentsManifest is the top-level structure of the manifest generated by
// podplane/components.
type ComponentsManifest struct {
	Components Components `json:"components"`
}

// ComponentImageFilter selects component images for download while preserving
// the full manifest. An empty Providers list matches provider-neutral images
// only; "all" matches every provider-specific image. Addon images are included
// only when Addons names the component or contains "all".
type ComponentImageFilter struct {
	Archs     []string
	Providers []string
	Addons    []string
}

// Components lists rendered component chart images.
type Components struct {
	Version string            `json:"version"`
	Source  *ComponentsSource `json:"source,omitempty"`
	Images  []ComponentImage  `json:"images"`
}

// ComponentsSource describes the Git repository used by platform-components.
type ComponentsSource struct {
	URL string              `json:"url"`
	Ref ComponentsSourceRef `json:"ref,omitempty"`
}

// ComponentsSourceRef selects a Git ref for the components source. Exactly one
// field should be set when a source is used for Git caching.
type ComponentsSourceRef struct {
	Branch string `json:"branch,omitempty"`
	Tag    string `json:"tag,omitempty"`
	Semver string `json:"semver,omitempty"`
	Commit string `json:"commit,omitempty"`
}

// validateComponentsSource verifies that a components source selects one Git ref.
func validateComponentsSource(source *ComponentsSource) error {
	if strings.TrimSpace(source.URL) == "" {
		return fmt.Errorf("components source url is required")
	}
	refs := 0
	if source.Ref.Branch != "" {
		refs++
	}
	if source.Ref.Tag != "" {
		refs++
	}
	if source.Ref.Semver != "" {
		refs++
	}
	if source.Ref.Commit != "" {
		refs++
	}
	if refs != 1 {
		return fmt.Errorf("components source ref must set exactly one of branch, tag, semver, or commit")
	}
	return nil
}

// ComponentImage describes one source image rendered by a component chart.
type ComponentImage struct {
	Components []string `json:"components,omitempty"`
	Image      string   `json:"image"`
	Digest     string   `json:"digest"`
	Size       int64    `json:"size"`
	Platform   string   `json:"platform,omitempty"`
	Index      string   `json:"index,omitempty"`
	Providers  []string `json:"providers,omitempty"`
	Addon      bool     `json:"addon,omitempty"`
	Cached     bool     `json:"cached,omitempty"`
}

// componentLabel formats an image's component ownership for diagnostics.
func (i ComponentImage) componentLabel() string {
	return strings.Join(i.Components, ",")
}

// ResetCached clears local cache-state markers from all component images.
func (m *ComponentsManifest) ResetCached() {
	for i := range m.Components.Images {
		m.Components.Images[i].Cached = false
	}
}

// MarkCached marks one component image entry as present in the local cache.
func (m *ComponentsManifest) MarkCached(index int) {
	if index < 0 || index >= len(m.Components.Images) {
		return
	}
	m.Components.Images[index].Cached = true
}

// DownloadImageIndexes returns the indexes of component images that should be
// downloaded for the given architecture, provider, and addon selection. Indexes
// are returned instead of image copies so callers can mark local cache state on
// the original full manifest.
func (m *ComponentsManifest) DownloadImageIndexes(filter ComponentImageFilter) []int {
	wantedArchs := map[string]bool{}
	for _, arch := range filter.Archs {
		wantedArchs[arch] = true
	}
	providers := newNameSelector(filter.Providers)
	addons := newNameSelector(filter.Addons)
	indexes := make([]int, 0, len(m.Components.Images))
	for i, image := range m.Components.Images {
		if image.Platform != "" && !wantedArchs[archFromPlatform(image.Platform)] {
			continue
		}
		if !providers.includesAny(image.Providers) {
			continue
		}
		if image.Addon && !addons.includesAny(image.Components) {
			continue
		}
		indexes = append(indexes, i)
	}
	return indexes
}

type nameSelector struct {
	all    bool
	values map[string]bool
}

func newNameSelector(values []string) nameSelector {
	selected := nameSelector{values: map[string]bool{}}
	for _, value := range values {
		for _, part := range strings.Split(value, ",") {
			name := strings.ToLower(strings.TrimSpace(part))
			if name == "" {
				continue
			}
			if name == "all" {
				selected.all = true
				continue
			}
			selected.values[name] = true
		}
	}
	return selected
}

func (s nameSelector) includes(name string) bool {
	if s.all {
		return true
	}
	return s.values[strings.ToLower(strings.TrimSpace(name))]
}

func (s nameSelector) includesAny(values []string) bool {
	if len(values) == 0 {
		return true
	}
	if s.all {
		return true
	}
	for _, value := range values {
		if s.includes(value) {
			return true
		}
	}
	return false
}

// archFromPlatform returns the architecture component from an OCI platform string.
func archFromPlatform(platform string) string {
	parts := strings.Split(platform, "/")
	if len(parts) < 2 {
		return ""
	}
	return parts[1]
}
